import { defineComponentStyle } from "@yamada-ui/react"

export const slideFadeStyle = defineComponentStyle({
  base: {
    w: "full",
  },
})

export type SlideFadeStyle = typeof slideFadeStyle

import { useState } from "react"
import { page, render } from "#test/browser"
import { SlideFade } from "./slide-fade"

describe("<SlideFade />", () => {
  test("fade-in and fade-out work correctly", async () => {
    const TestComponent = () => {
      const [open, setOpen] = useState(false)

      return (
        <>
          <button onClick={() => setOpen((prev) => !prev)}>button</button>
          <SlideFade open={open}>SlideFade</SlideFade>
        </>
      )
    }

    const { user } = await render(<TestComponent />)

    const button = page.getByRole("button", { name: /button/i })
    const slideFade = page.getByText("SlideFade")
    await expect.element(slideFade).toHaveStyle({ opacity: "0" })

    await user.click(button)
    await expect.element(slideFade).toHaveStyle({ opacity: "1" })

    await user.click(button)
    await expect.element(slideFade).toHaveStyle({ opacity: "0" })
  })

  test("fade-in and fade-out work correctly when `initial` is passed to an `initial` property", async () => {
    const TestComponent = () => {
      const [open, setOpen] = useState(false)

      return (
        <>
          <button onClick={() => setOpen((prev) => !prev)}>button</button>
          <SlideFade initial="initial" open={open}>
            SlideFade
          </SlideFade>
        </>
      )
    }

    const { user } = await render(<TestComponent />)

    const button = page.getByRole("button", { name: /button/i })
    const slideFade = page.getByText("SlideFade")
    await expect.element(slideFade).toHaveStyle({ opacity: "0" })

    await user.click(button)
    await expect.element(slideFade).toHaveStyle({ opacity: "1" })

    await user.click(button)
    await expect.element(slideFade).toHaveStyle({ opacity: "0" })
  })

  test("default offset is set correctly", async () => {
    await render(<SlideFade>SlideFade</SlideFade>)

    await expect
      .element(page.getByText("SlideFade"))
      .toHaveStyle("transform: matrix(1, 0, 0, 1, 0, 8)")
  })

  test("applies offsetX correctly", async () => {
    await render(<SlideFade offsetX={10}>SlideFade</SlideFade>)

    await expect
      .element(page.getByText("SlideFade"))
      .toHaveStyle("transform: matrix(1, 0, 0, 1, 10, 8)")
  })

  test("applies offsetY correctly", async () => {
    await render(<SlideFade offsetY={10}>SlideFade</SlideFade>)

    await expect
      .element(page.getByText("SlideFade"))
      .toHaveStyle("transform: matrix(1, 0, 0, 1, 0, 10)")
  })

  test("unmountOnExit works correctly", async () => {
    const TestComponent = () => {
      const [open, setOpen] = useState(false)

      return (
        <>
          <button onClick={() => setOpen((prev) => !prev)}>button</button>
          <SlideFade open={open} unmountOnExit>
            SlideFade
          </SlideFade>
        </>
      )
    }

    const { user } = await render(<TestComponent />)

    const button = page.getByRole("button", { name: /button/i })
    await expect
      .element(page.getByText("SlideFade").query())
      .not.toBeInTheDocument()

    await user.click(button)
    await expect.element(page.getByText("SlideFade")).toBeVisible()

    await user.click(button)
    await expect
      .element(page.getByText("SlideFade").query())
      .not.toBeInTheDocument()
  })
})

"use client"

import type { Variants } from "motion/react"
import type { ThemeProps } from "@yamada-ui/react"
import type {
  HTMLMotionProps,
  MotionTransitionVariants,
  WithTransitionProps,
} from "../motion"
import type { SlideFadeStyle } from "./slide-fade.style"
import { AnimatePresence } from "motion/react"
import { useMemo } from "react"
import { createComponent } from "@yamada-ui/react"
import { createTransition, motion } from "../motion"
import { slideFadeStyle } from "./slide-fade.style"

export const slideFadeVariants: Variants = {
  enter: ({ delay, duration, enter, transition, transitionEnd } = {}) => ({
    opacity: 1,
    transition: createTransition.enter(transition?.enter)(delay, duration),
    transitionEnd: transitionEnd?.enter,
    x: 0,
    y: 0,
    ...enter,
  }),
  exit: ({
    delay,
    duration,
    exit,
    offsetX,
    offsetY,
    reverse,
    transition,
    transitionEnd,
  } = {}) => ({
    opacity: 0,
    transition: createTransition.exit(transition?.exit)(delay, duration),
    ...(reverse
      ? { transitionEnd: transitionEnd?.exit, x: offsetX, y: offsetY }
      : { transitionEnd: { x: offsetX, y: offsetY, ...transitionEnd?.exit } }),
    ...exit,
  }),
  initial: ({
    delay,
    duration,
    initial,
    offsetX,
    offsetY,
    transition,
    transitionEnd,
  }) => ({
    opacity: 0,
    transition: createTransition.exit(transition?.exit)(delay, duration),
    transitionEnd: transitionEnd?.exit,
    x: offsetX,
    y: offsetY,
    ...initial,
  }),
} satisfies MotionTransitionVariants

export interface SlideFadeProps
  extends WithTransitionProps<HTMLMotionProps>, ThemeProps<SlideFadeStyle> {
  /**
   * The offset on the horizontal or `x` axis.
   *
   * @default 0
   */
  offsetX?: number | string
  /**
   * The offset on the vertical or `y` axis.
   *
   * @default 8
   */
  offsetY?: number | string
  /**
   * If `true`, the element will be transitioned back to the offset when it leaves. Otherwise, it'll only fade out.
   *
   * @default true
   */
  reverse?: boolean
}

const {
  PropsContext: SlideFadePropsContext,
  usePropsContext: useSlideFadePropsContext,
  withContext,
} = createComponent<SlideFadeProps, SlideFadeStyle>(
  "slide-fade",
  slideFadeStyle,
)

export { SlideFadePropsContext, useSlideFadePropsContext }

/**
 * `SlideFade` is a component that gradually shows or hides an element while moving it from a specified position.
 *
 * @see https://yamada-ui.com/docs/components/slide-fade
 */
export const SlideFade = withContext<"div", SlideFadeProps>(
  ({
    delay,
    duration,
    offsetX = 0,
    offsetY = 8,
    open: openProp,
    reverse = true,
    transition,
    transitionEnd,
    unmountOnExit,
    ...rest
  }) => {
    const animate = openProp || unmountOnExit ? "enter" : "exit"
    const open = unmountOnExit ? openProp && unmountOnExit : true

    const custom = useMemo(
      () => ({
        delay,
        duration,
        offsetX,
        offsetY,
        reverse,
        transition,
        transitionEnd,
      }),
      [delay, duration, offsetX, offsetY, reverse, transition, transitionEnd],
    )

    return (
      <AnimatePresence custom={custom}>
        {open ? (
          <motion.div
            animate={animate}
            custom={custom}
            exit="exit"
            initial="exit"
            variants={slideFadeVariants}
            {...rest}
          />
        ) : null}
      </AnimatePresence>
    )
  },
)()
